+/// Text wrapping mode.
+#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
+pub enum WrapMode {
+    /// No wrapping - lines extend beyond viewport.
+    #[default]
+    None,
+    /// Wrap at character boundaries.
+    Char,
+    /// Wrap at word boundaries.
+    Word,
+}
+
+/// Viewport configuration.
+#[derive(Clone, Copy, Debug, Default)]
+pub struct Viewport {
+    pub x: u32,
+    pub y: u32,
+    pub width: u32,
+    pub height: u32,
+}
+
+impl Viewport {
+    /// Create a new viewport.
+    #[must_use]
+    pub fn new(x: u32, y: u32, width: u32, height: u32) -> Self {
+        Self {
+            x,
+            y,
+            width,
+            height,
+        }
+    }
+}
+
+/// Selection range.
+#[derive(Clone, Copy, Debug, Default)]
+pub struct Selection {
+    pub start: usize,
+    pub end: usize,
+    pub style: Style,
+}
+
+impl Selection {
+    /// Create a new selection.
+    #[must_use]
+    pub fn new(start: usize, end: usize, style: Style) -> Self {
+        Self { start, end, style }
+    }
+
+    /// Check if empty.
+    #[must_use]
+    pub fn is_empty(&self) -> bool {
+        self.start == self.end
+    }
+
+    /// Get normalized (start <= end) selection.
+    #[must_use]
+    pub fn normalized(&self) -> Self {
+        if self.start <= self.end {
+            *self
+        } else {
+            Self {
+                start: self.end,
+                end: self.start,
+                style: self.style,
+            }
+        }
+    }
+
+    /// Check if position is within selection.
+    #[must_use]
+    pub fn contains(&self, pos: usize) -> bool {
+        let norm = self.normalized();
+        pos >= norm.start && pos < norm.end
+    }
+}
+
+/// Local (viewport) selection based on screen coordinates.
+#[derive(Clone, Copy, Debug, Default)]
+pub struct LocalSelection {
+    pub anchor_x: u32,
+    pub anchor_y: u32,
+    pub focus_x: u32,
+    pub focus_y: u32,
+    pub style: Style,
+}
+
+impl LocalSelection {
+    /// Create a new local selection.
+    #[must_use]
+    pub fn new(anchor_x: u32, anchor_y: u32, focus_x: u32, focus_y: u32, style: Style) -> Self {
+        Self {
+            anchor_x,
+            anchor_y,
+            focus_x,
+            focus_y,
+            style,
+        }
+    }
+
+    /// Normalize selection rectangle.
+    #[must_use]
+    pub fn normalized(&self) -> (u32, u32, u32, u32) {
+        let min_x = self.anchor_x.min(self.focus_x);
+        let max_x = self.anchor_x.max(self.focus_x);
+        let min_y = self.anchor_y.min(self.focus_y);
+        let max_y = self.anchor_y.max(self.focus_y);
