+/// View into a text buffer with viewport and rendering options.
+pub struct TextBufferView<'a> {
+    buffer: &'a TextBuffer,
+    viewport: Viewport,
+    wrap_mode: WrapMode,
+    wrap_width: Option<u32>,
+    scroll_x: u32,
