+                if current_width + g_width > wrap_width && current_width > 0 {
+                    let (break_byte, break_width, break_index) = if self.wrap_mode == WrapMode::Word
+                    {
+                        last_break.unwrap_or((byte_idx, current_width, i))
+                    } else {
+                        (byte_idx, current_width, i)
+                    };
