+
+                    start_byte = break_byte;
+                    current_width = 0;
+                    last_break = None;
+                    i = break_index;
+
+                    if self.wrap_mode == WrapMode::Word {
+                        while i < graphemes.len() {
+                            let (b, g) = graphemes[i];
+                            if b < start_byte {
+                                i += 1;
+                                continue;
+                            }
+                            if g.chars().all(|c| c.is_whitespace()) {
+                                start_byte = b + g.len();
+                                i += 1;
+                            } else {
+                                break;
+                            }
+                        }
+                    }
