+            if start_byte <= line.len() {
+                lines.push(VirtualLine {
+                    source_line: line_idx,
+                    byte_start: line_start_byte + start_byte,
+                    byte_end: line_start_byte + line.len(),
+                    width: current_width,
+                    is_wrap: start_byte > 0,
+                });
+            }
+        }
